            ru("\\u0411\\u043b\\u043e\\u043a \\u043a\\u043b\\u0430\\u0441\\u0442\\u0435\\u0440\\u0438\\u0437\\u0430\\u0446\\u0438\\u0438 \\u0441\\u0442\\u0440\\u043e\\u0438\\u0442\\u0441\\u044f \\u043d\\u0430 `KMeans`, `Birch`, `AgglomerativeClustering`, `PCA`, `StandardScaler`, \\u0430 \\u0442\\u0430\\u043a\\u0436\\u0435 \\u043d\\u0430 \\u0440\\u0430\\u0441\\u0447\\u0451\\u0442\\u0435 \\u043c\\u0435\\u0442\\u0440\\u0438\\u043a \\u043a\\u0430\\u0447\\u0435\\u0441\\u0442\\u0432\\u0430 \\u043a\\u043b\\u0430\\u0441\\u0442\\u0435\\u0440\\u043e\\u0432 \\u0438 \\u0441\\u0442\\u0430\\u0431\\u0438\\u043b\\u044c\\u043d\\u043e\\u0441\\u0442\\u0438 \\u0440\\u0430\\u0437\\u0431\\u0438\\u0435\\u043d\\u0438\\u044f."),
